  ('judicial-f0899a01-moex-00276', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政行為明確性原則之敘述，下列何者錯誤？', '["明確性原則要求行政行為之內容必須明確，使人民知悉規制之內容", "明確性原則之目的，係為追求行政行為之可預見性", "行政機關作成沒入處分時，沒入之標的已滅失，係違反明確性原則", "行政機關之裁罰處分，未記載罰鍰數額，係違反明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00277', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '有關法律保留之敘述，下列何者錯誤？', '["執行法律之細節性、技術性次要事項，則得由主管機關發布命令為必要之規範", "以法律授權主管機關發布命令為補充規定時，其授權應符合具體明確之原則", "剝奪人民生命或限制人民身體自由者，得以制定命令之方式為之", "何種事項應以法律直接規範或得委由命令予以規定，與所謂規範密度有關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
