  ('judicial-f0899a01-moex-00280', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政法之法律關係，下列敘述何者錯誤？', '["其當事人僅限於國家與人民，不包括國家與公務員", "人民主觀之公權利，包括消極防禦權與積極請求權", "國家作為公權力主體，得課人民作為、不作為義務", "地方自治團體亦得作為公權利主體，對國家主張給付請求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
