  ('judicial-f0899a01-moex-00282', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依據中央行政機關組織基準法之規定，關於行政機關名稱之敘述，下列何者錯誤？', '["稱部者，屬一級機關", "稱委員會者，屬二級機關", "稱署者，屬三級機關", "稱分局者，屬四級機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00283', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依地方制度法規定，自治條例與中央機關基於法律授權訂定之法規命令發生牴觸時，其效力為何？', '["自治條例無效", "法規命令無效", "兩者均有效，依特別法優先於普通法，決定適用順序", "兩者均有效，依後法優先於前法，決定適用順序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00284', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '法規未規定行政機關之管轄權致無法定土地管轄者，應如何定之？', '["關於不動產之事件，依不動產所有人之戶籍地", "關於企業經營之事件，依經營企業之處所", "關於自然人之事件，依其指定之處所所在地", "關於法人之事件，依其負責人之住所地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00285', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於數行政機關對於管轄權有爭議時之處理，下列敘述何者正確？', '["由其共同上級機關決定之，無共同上級機關時，由行政院定之", "由其共同上級機關決定之，無共同上級機關時，由法務部定之", "人民對行政機關所為指定管轄之決定，得向其上級機關聲明異議", "人民對行政機關所為指定管轄之決定，不得聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "669700b77e3f", "answer_pdf_sha1": "2dc45c392fdc", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
